        private static byte[] SerializeValueShapeShard(MetaCliModel model, SaveIndexes saveIndexes)
        {
            var builder = new StringBuilder();
            var rowIds = new HashSet<string>(StringComparer.OrdinalIgnoreCase);
            builder.Append("<?xml version=\"1.0\" encoding=\"utf-8\"?>\n");
            builder.Append("<MetaCli>\n");
            builder.Append("  <ValueShapeList>\n");
            foreach (var row in model.ValueShapeList.OrderBy(row => row.Id, StringComparer.OrdinalIgnoreCase))
            {
                ArgumentNullException.ThrowIfNull(row);
                var rowId = RequireIdentity(row.Id, "Entity 'ValueShape' contains a row with empty Id.");
                if (!rowIds.Add(rowId))
                {
                    throw new InvalidOperationException($"Entity 'ValueShape' contains duplicate Id '{rowId}'.");
                }
                builder.Append("    <ValueShape Id=\"");
                AppendXmlAttribute(builder, rowId);
                builder.Append('"');
                var valueArityId = RequireIdentity(row.ValueArity?.Id, $"Relationship 'ValueShape.ValueArityId' on row 'ValueShape:{row.Id}' is empty.");
                if (!saveIndexes.ValueArityListById.TryGetValue(valueArityId, out var valueArityCanonical) || !ReferenceEquals(valueArityCanonical, row.ValueArity))
                {
                    throw new InvalidOperationException($"Relationship 'ValueShape.ValueArityId' on row 'ValueShape:{row.Id}' references an object that is not the canonical row for Id '{valueArityId}'.");
                }
                builder.Append(' ');
                builder.Append("ValueArityId");
                builder.Append("=\"");
                AppendXmlAttribute(builder, valueArityId);
                builder.Append('"');
                builder.Append(">\n");
                if (!string.IsNullOrWhiteSpace(row.AllowsOptionLikeValue))
                {
                    AppendElement(builder, "AllowsOptionLikeValue", row.AllowsOptionLikeValue!, "      ");
                }
                if (!string.IsNullOrWhiteSpace(row.Description))
                {
                    AppendElement(builder, "Description", row.Description!, "      ");
                }
                AppendElement(builder, "Name", RequireText(row.Name, $"Entity 'ValueShape' row '{row.Id}' is missing required property 'Name'."), "      ");
                if (!string.IsNullOrWhiteSpace(row.ValueLabel))
                {
                    AppendElement(builder, "ValueLabel", row.ValueLabel!, "      ");
                }
                builder.Append("    </ValueShape>\n");
            }
            builder.Append("  </ValueShapeList>\n");
            builder.Append("</MetaCli>\n");
            return Utf8NoBom.GetBytes(builder.ToString());
        }

