            public Dictionary<string, Parameter> ParameterListById => parameterListById ??= BuildById(model.ParameterList, row => row.Id, "Parameter");

            private Dictionary<string, ParameterGroup>? parameterGroupListById;

            public Dictionary<string, ParameterGroup> ParameterGroupListById => parameterGroupListById ??= BuildById(model.ParameterGroupList, row => row.Id, "ParameterGroup");

            private Dictionary<string, ParameterGroupMember>? parameterGroupMemberListById;

            public Dictionary<string, ParameterGroupMember> ParameterGroupMemberListById => parameterGroupMemberListById ??= BuildById(model.ParameterGroupMemberList, row => row.Id, "ParameterGroupMember");

            private Dictionary<string, PositionalArgument>? positionalArgumentListById;

            public Dictionary<string, PositionalArgument> PositionalArgumentListById => positionalArgumentListById ??= BuildById(model.PositionalArgumentList, row => row.Id, "PositionalArgument");

            private Dictionary<string, ValueArity>? valueArityListById;

            public Dictionary<string, ValueArity> ValueArityListById => valueArityListById ??= BuildById(model.ValueArityList, row => row.Id, "ValueArity");

            private Dictionary<string, ValueShape>? valueShapeListById;

